alter type public.task_status add value if not exists 'running';
create table public.agent_runs (id uuid primary key default gen_random_uuid(), agent_id uuid references public.agents(id) on delete set null, content_task_id uuid references public.content_tasks(id) on delete cascade, user_id uuid references public.profiles(id) on delete set null, status public.task_status not null default 'pending', input jsonb not null default '{}'::jsonb, output jsonb, error text, started_at timestamptz, completed_at timestamptz, created_at timestamptz not null default now());
create table public.image_tasks (id uuid primary key default gen_random_uuid(), user_id uuid references public.profiles(id) on delete cascade, prompt text not null, model text, size text, status public.task_status not null default 'pending', result jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.video_tasks (id uuid primary key default gen_random_uuid(), user_id uuid references public.profiles(id) on delete cascade, prompt text not null, model text, duration_seconds integer, status public.task_status not null default 'pending', result jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.system_logs (id uuid primary key default gen_random_uuid(), level text not null, event text not null, user_id uuid references public.profiles(id) on delete set null, task_id uuid references public.content_tasks(id) on delete set null, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now());
alter table public.agent_runs enable row level security; alter table public.image_tasks enable row level security; alter table public.video_tasks enable row level security; alter table public.system_logs enable row level security;
create policy "agent runs own or admin" on public.agent_runs for select using (user_id=auth.uid() or public.is_admin());
create policy "image tasks own or admin" on public.image_tasks for select using (user_id=auth.uid() or public.is_admin());
create policy "video tasks own or admin" on public.video_tasks for select using (user_id=auth.uid() or public.is_admin());
create policy "admin system logs" on public.system_logs for select using (public.is_admin());
